import React, { useMemo } from 'react'
import useData, { getPlansData } from '../useData'
import useSplitPaymentStore from '../useSplitPaymentStore'

export function PlanCard({ plan, onClick, activePlan }) {
    if (plan) {
        const { planTitle, planDuration, planTag, id } = plan
        const getClass = () => activePlan && activePlan.id === id ? 'flex flex-col relative border-4 border-blue-400 rounded-lg bg-sky-100 cursor-pointer text-indigo-500 justify-center item-center' : 'flex flex-col text-white relative border-4 border-indigo-500 rounded-lg bg-blue-800 cursor-pointer justify-center item-center'
        return (
            <div className={getClass()} onClick={() => onClick(plan)}>
                <div className='p-2 text-4xl'>{planTitle}</div>
                <div className='p-2 text-xl'>{planDuration + ' ' + 'months'}</div>
            </div>
        )
    }
}

export function ShimmerPlans({ count }) {
    return Array.from({ length: count }, () => {
        return <div className='p-2 border-4 border-grey-100 rounded-lg bg-gray-200'></div>
    })
}
function Plans() {
    const { data, loading, error } = useData(getPlansData)
    const { setActivePlan, activePlan } = useSplitPaymentStore((s) => s)

    function handleClick(plan) {
        setActivePlan(plan)
    }
    if (loading) {
        return <div className='grid grid-cols-4 gap-4 p-4 h-[132px]'><ShimmerPlans count={4} /></div>
    }
    if (error) {
        return <div>{error.message}</div>
    }
    if (data) {
        return (
            <div className='grid grid-cols-4 gap-4 p-4'>
                {data.map((plan) => {
                    return (<PlanCard activePlan={activePlan} key={plan.id} plan={plan} onClick={handleClick} />)
                })}
            </div>
        )
    }
}

export default Plans
